#' @param infected   Infectious-count census Column (`nodes$I`), `slice_len == n_nodes`.
#' @param population Per-node population census Column (`nodes$N`); the FOI denominator.
#' @param beta       Transmission-coefficient grid (`n_ticks x n_nodes`, from [values_map()]).
#' @param seasonality Seasonal-modifier grid (`n_ticks x n_nodes`, from [values_map()]).
#' @param network    An `n_nodes x n_nodes` numeric coupling matrix.
#' @param foi        A 2-D f64 Column (`(n_ticks-1) x n_nodes`); column `tick` is overwritten.
#' @param tick       0-based tick index: reads `beta[tick]`/`seasonality[tick]` and
#'   `infected[tick]`/`population[tick]` (the start-of-interval census), writes `foi[tick]`.
#' @return `NULL` (invisibly); the result is written into `foi`.
#' @export
calc_foi <- function(infected, population, beta, seasonality, network, foi, tick) .Call(wrap__calc_foi, infected, population, beta, seasonality, network, foi, tick)

#' Stochastic transmission Sâ†’`to_state`, returning new infections per node.
#'
#' Converts column `tick` of `foi` to a per-node probability `1 - exp(-foi)` (once per
#' node), then for each susceptible agent moves it â€” with that probability â€” into
#' `to_state` (`E` or `I`), setting its u16 `timer` from `duration` (the incubation or
#' infectious period). The node census is NOT touched: the per-node count of new
#' infections is RETURNED, and the caller applies the `S` â†“ / `to_state` â†‘ delta and
#' records incidence as its model requires (it knows whether this is Sâ†’E or Sâ†’I).
#'
#' @param state    Per-agent `u8` state Column (mutated).
#' @param timer    Per-agent `u16` timer Column (mutated; set from `duration`).
#' @param nodeid   Per-agent `u16` 0-based node-id Column.
#' @param count    Number of active agents to process.
#' @param foi      `n_ticks x n_nodes` f64 FOI Column (from [calc_foi()]); column `tick` read.
#' @param tick     0-based tick index.
#' @param to_state State code new infections enter (`laser_states()[["E"]]` or `[["I"]]`).
#' @param duration A Distribution from which the receiving state's timer is drawn.
#' @return An integer vector of new infections per node (length `n_nodes`).
#' @export
transmission <- function(state, timer, nodeid, count, foi, tick, to_state, duration) .Call(wrap__transmission, state, timer, nodeid, count, foi, tick, to_state, duration)

#' Stochastic transmission Sâ†’I into an ABSORBING `I` (the SI model), returning new
#' infections per node.
#'
#' Like [transmission()] but the agent enters `I` permanently â€” no `timer` is set (`I`
#' is terminal in SI). Returns the per-node count of new infections; the caller applies
#' the `S` â†“ / `I` â†‘ delta.
#'
#' @param state    Per-agent `u8` state Column (mutated; Sâ†’I).
#' @param nodeid   Per-agent `u16` 0-based node-id Column.
#' @param count    Number of active agents to process.
#' @param foi      `n_ticks x n_nodes` f64 FOI Column; column `tick` read.
#' @param tick     0-based tick index.
#' @return An integer vector of new infections per node (length `n_nodes`).
#' @export
transmission_si <- function(state, nodeid, count, foi, tick) .Call(wrap__transmission_si, state, nodeid, count, foi, tick)

#' Advance Mâ†’S (maternal waning) and Eâ†’I (incubation) for one tick â€” SI / SEI.
#'
#' `I` is terminal (no exit). Returns `list(waned, onset)` of per-node counts.
#'
#' @param state   Per-agent `u8` state Column (mutated).
#' @param timer   Per-agent `u16` timer Column (mutated; Eâ†’I draws an infectious timer).
#' @param nodeid  Per-agent `u16` 0-based node-id Column.
#' @param count   Number of active agents to process.
#' @param n_nodes Number of nodes (the length of each returned vector).
#' @param inf_duration A Distribution for the infectious period set on Eâ†’I.
#' @return `list(waned = integer[n_nodes], onset = integer[n_nodes])`.
#' @export
step_si <- function(state, timer, nodeid, count, n_nodes, inf_duration) .Call(wrap__step_si, state, timer, nodeid, count, n_nodes, inf_duration)

#' Advance Mâ†’S, Eâ†’I, and Iâ†’`absorbing_state` for one tick â€” SIS / SIR / SEIS / SEIR.
#'
#' `absorbing_state` is the untimed destination of the infectious period: `S` (SIS/SEIS)
#' or `R` (SIR/SEIR). Returns `list(waned, onset, cleared)` of per-node counts (`cleared`
#' is the Iâ†’`absorbing_state` flow).
#'
#' @param state,timer,nodeid,count,n_nodes  As in [step_si()].
#' @param inf_duration   A Distribution for the infectious period set on Eâ†’I.
#' @param absorbing_state State code I clears to (`laser_states()[["S"]]` or `[["R"]]`).
#' @return `list(waned, onset, cleared)` of `integer[n_nodes]`.
#' @export
step_sir <- function(state, timer, nodeid, count, n_nodes, inf_duration, absorbing_state) .Call(wrap__step_sir, state, timer, nodeid, count, n_nodes, inf_duration, absorbing_state)

#' Advance Mâ†’S, Eâ†’I, Iâ†’R (with waning immunity), and Râ†’S for one tick â€” SIRS / SEIRS.
#'
#' On Iâ†’R a fresh immunity timer is drawn from `imm_duration`; Râ†’S fires when it expires.
#' Returns `list(waned, onset, recovered, waned_r)` of per-node counts.
#'
#' @param state,timer,nodeid,count,n_nodes  As in [step_si()].
#' @param inf_duration A Distribution for the infectious period set on Eâ†’I.
#' @param imm_duration A Distribution for the immunity period set on Iâ†’R.
#' @return `list(waned, onset, recovered, waned_r)` of `integer[n_nodes]`.
#' @export
step_sirs <- function(state, timer, nodeid, count, n_nodes, inf_duration, imm_duration) .Call(wrap__step_sirs, state, timer, nodeid, count, n_nodes, inf_duration, imm_duration)

#' Generic timed transition `from_state -> to_state` into an UNTIMED destination.
#'
#' For each agent in `from_state`, decrements its u16 `timer`; on expiry the agent moves
#' to `to_state` (timer left at 0). Returns the per-node count of transitions. Compose
#' these (downstream-first) to build models beyond the named menagerie; apply the counts
#' with `move_count`. Generalizes the Mâ†’S / Râ†’S / Iâ†’{S,R} legs.
#'
#' @param state,timer,nodeid,count,n_nodes  As in [step_si()].
#' @param from_state Integer state code an agent must occupy to be eligible.
#' @param to_state   Integer (untimed) state code an agent moves to on expiry.
#' @return An integer vector of per-node transition counts (length `n_nodes`).
#' @export
step_timer_expire <- function(state, timer, nodeid, count, n_nodes, from_state, to_state) .Call(wrap__step_timer_expire, state, timer, nodeid, count, n_nodes, from_state, to_state)

#' Generic timed transition `from_state -> to_state` into a TIMED destination.
#'
#' Like [step_timer_expire()] but on expiry the agent's `timer` is reset to a fresh draw
#' from `duration` (the destination state's own clock â€” e.g. Eâ†’I sets the infectious
#' period, Iâ†’R sets a waning-immunity period). Returns per-node transition counts.
#'
#' @param state,timer,nodeid,count,n_nodes  As in [step_si()].
#' @param from_state Integer state code an agent must occupy to be eligible.
#' @param to_state   Integer state code an agent moves to on expiry.
#' @param duration   A Distribution for the destination state's timer.
#' @return An integer vector of per-node transition counts (length `n_nodes`).
#' @export
step_timer_expire_set <- function(state, timer, nodeid, count, n_nodes, from_state, to_state, duration) .Call(wrap__step_timer_expire_set, state, timer, nodeid, count, n_nodes, from_state, to_state, duration)

#' Apply constant-population SIR vital dynamics for one tick.
#'
#' `rate` is a per-node daily death-HAZARD-rate grid (a values map; the caller
#' converts a crude death rate of annual deaths per 1000 people to a daily rate,
#' e.g. `cdr / 1000 / 365`). For each of the first `count` agents, this converts the
#' node's rate to a probability `1 - exp(-rate)` (once per node, like transmission)
#' and, with that probability, "unalives" the agent and replaces it with a newborn:
#' the agent's `state` is reset to Susceptible and its `timer` to 0.
#'
#' The S/I/R node census is updated IN PLACE at column `tick + 1` (the working
#' column the caller has already carried forward): a death out of I decrements `I`
#' and increments `S`; a death out of R decrements `R` and increments `S`; a death
#' out of S nets to zero. Every event (from any compartment) is counted per node and
#' written to BOTH the `births` and `deaths` flow reports for `tick` (equal under
#' constant population). Agents are assumed to be in S, I, or R (it is the SIR
#' variant). Parallelized with private per-thread node buffers summed at the end.
#'
#' @param state   Per-agent `u8` state Column (mutated; deaths reset to Susceptible).
#' @param timer   Per-agent `u8` countdown Column (mutated; deaths reset to 0).
#' @param nodeid  Per-agent `u16` 0-based node-id Column.
#' @param count   Number of active agents to process.
#' @param rate    Per-node daily death-hazard-rate grid (`n_ticks x n_nodes`, from
#'   [values_map()]); column `tick` is read.
#' @param s_count,i_count,r_count  `n_ticks x n_nodes` i32 census Columns kept in
#'   sync (mutated at column `tick + 1`).
#' @param births,deaths  `(n_ticks-1) x n_nodes` i32 flow Columns; column `tick`
#'   receives the per-node event counts (equal; mutated).
#' @param tick    0-based tick index.
#' @return `NULL` (invisibly); the Columns are modified in place.
#' @export
constant_pop_vitals_sir <- function(state, timer, nodeid, count, rate, s_count, i_count, r_count, births, deaths, tick) .Call(wrap__constant_pop_vitals_sir, state, timer, nodeid, count, rate, s_count, i_count, r_count, births, deaths, tick)

#' Import new infectious cases from a schedule, activating reserved agent slots.
#'
#' For the given `tick`, scans the schedule (parallel `sched_tick` / `sched_node` /
#' `sched_count` vectors) and, for every entry whose `sched_tick == tick`, activates
#' `sched_count` new agents in node `sched_node`: each takes the next free slot after
#' the active `count`, is set Infectious with a `timer` drawn from `duration`, and
#' has its `nodeid` set. The new agents must fit in the reserved capacity (the
#' `state`/`timer`/`nodeid` Columns are allocated larger than the initial `count`).
#' Per-node import counts are added to the I census at column `tick + 1` and written
#' to the `importations` flow at column `tick`.
#'
#' Returns the new active agent count (the caller stores it back into `people$count`).
#' Sequential â€” it touches only the handful of imported slots, not all agents.
#'
#' @param state   Per-agent `u8` state Column (capacity-sized; imported slots set to I).
#' @param timer   Per-agent `u8` timer Column (imported slots set from `duration`).
#' @param nodeid  Per-agent `u16` node-id Column (imported slots set to their node).
#' @param count   Current active agent count (the first free slot).
#' @param i_count `n_ticks x n_nodes` i32 I census Column (mutated at `tick + 1`).
#' @param importations `(n_ticks-1) x n_nodes` i32 flow Column (set at `tick`).
#' @param sched_tick,sched_node,sched_count  Equal-length integer schedule vectors.
#' @param duration A Distribution for the imported cases' infectious timer.
#' @param tick    0-based tick index.
#' @return The new active agent count (`count` plus the number imported this tick).
#' @export
import_infections <- function(state, timer, nodeid, count, i_count, importations, sched_tick, sched_node, sched_count, duration, tick) .Call(wrap__import_infections, state, timer, nodeid, count, i_count, importations, sched_tick, sched_node, sched_count, duration, tick)

#' Build an [AliasedDistribution] from a vector of non-negative bin counts.
#'
#' The probability of drawing bin `i` (0-based) is `counts[i] / sum(counts)`. Counts
#' are rounded to whole numbers; they must be finite and non-negative and sum to a
#' positive total. A typical use is the per-age-bin population of a demographic
#' pyramid (e.g. males + females in each five-year band).
#'
#' @param counts A numeric vector of non-negative per-bin counts (length >= 1).
#' @return An `AliasedDistribution` object.
#' @examples
#' d <- aliased_distribution(c(10, 30, 60))   # bin 2 drawn ~60% of the time
#' table(d$sample_n(10000L))                  # 0-based bin indices
#' @export
aliased_distribution <- function(counts) .Call(wrap__aliased_distribution, counts)

#' Build a [KaplanMeierEstimator] from cumulative deaths by year.
#'
#' `cumulative_deaths[y]` is the number of a synthetic cohort dead by the end of year
#' `y`; it must be non-negative and monotonically non-decreasing. Values are rounded to
#' whole numbers. (A leading zero is prepended internally; do not include it yourself.)
#'
#' @param cumulative_deaths A non-decreasing numeric vector of cumulative deaths by
#'   year (length >= 1).
#' @return A `KaplanMeierEstimator` object.
#' @examples
#' # toy life table: 10 deaths/year for 80 years, then 100/year for 21 more
#' km <- kaplan_meier_estimator(cumsum(c(rep(10, 80), rep(100, 21))))
#' @export
kaplan_meier_estimator <- function(cumulative_deaths) .Call(wrap__kaplan_meier_estimator, cumulative_deaths)

#' Apply natural mortality for one tick, returning deaths per node by compartment.
#'
#' For each of the first `count` living agents (state != D) whose `dod` (an absolute
#' tick) is `<= tick`, sets the agent's `state` to D and tallies the death against the
#' compartment it occupied. Returns `list(m, s, e, i, r)` of per-node death counts; the
#' caller decrements those census compartments (and records the total deaths flow).
#'
#' @param state   Per-agent `u8` state Column (mutated; the deceased become D = 255).
#' @param dod     Per-agent `u32` date-of-death Column (an absolute tick index).
