#' @param tick    0-based tick index; agents with `dod <= tick` die.
#' @return `list(m, s, e, i, r)` of `integer[n_nodes]` death counts by source compartment.
#' @export
mortality <- function(state, dod, nodeid, count, n_nodes, tick) .Call(wrap__mortality, state, dod, nodeid, count, n_nodes, tick)

#' Apply crude-birth-rate births for one tick; newborns enter maternal immunity (M).
#'
#' For each of the first `count` living agents, draws a birth with per-node probability
#' `1 - exp(-birth_rate[node, tick])`. Each birth activates the next reserved slot as a
#' new agent: state M, `timer` from `maternal_duration`, `dob = tick`, and `dod = tick`
#' plus a Kaplanâ€“Meier age at death (from `km`). Returns `list(count, born)`: the new
#' active count (store it back into `people$count`) and the per-node birth count (add it
#' to the `M` census and a birth report). Capped at the allocated capacity.
#'
#' @param state    Per-agent `u8` state Column (capacity-sized; newborn slots set to M).
#' @param timer    Per-agent `u16` timer Column (newborn slots set from `maternal_duration`).
#' @param nodeid   Per-agent `u16` node-id Column (newborn slots set to the parent's node).
#' @param dob      Per-agent `i32` date-of-birth Column (newborn slots set to `tick`).
#' @param dod      Per-agent `u32` date-of-death Column (newborn slots set via `km`).
#' @param count    Current active agent count (the first free slot).
#' @param n_nodes  Number of nodes (the length of the returned `born` vector).
#' @param birth_rate `n_ticks x n_nodes` f64 daily-birth-rate grid; column `tick` is read.
#' @param maternal_duration A Distribution for the newborns' maternal-immunity timer.
#' @param km       A KaplanMeierEstimator giving each newborn its age at death.
#' @param tick     0-based tick index.
#' @return `list(count = <new active count>, born = integer[n_nodes])`.
#' @export
births <- function(state, timer, nodeid, dob, dod, count, n_nodes, birth_rate, maternal_duration, km, tick) .Call(wrap__births, state, timer, nodeid, dob, dod, count, n_nodes, birth_rate, maternal_duration, km, tick)

#' A parameterized probability distribution that can be sampled repeatedly.
#'
#' Build one with a family constructor such as `dist_normal()` or `dist_constant()`,
#' then either sample it from Rust via `sample()` (Pattern B: the caller owns the
#' RNG and passes it in), or from R via `$sample_one()` / `$sample_n()`.
#'
#' Draws are always floating-point. Callers that need integer values (e.g. a
#' whole-tick state timer) are responsible for rounding or truncating as
#' appropriate â€” the simulation kernels round to the nearest tick.
#'
#' The handle is opaque to R â€” it is passed to simulation kernels (e.g.
#' `step_sir` or `transmission`) by reference, so the same object can be reused
#' every tick and shared across all worker threads.
#'
#' @export
#'
#' @section Methods:
#'\subsection{Method `sample_one`}{
#'Draw a single sample using a thread-local RNG.
#'
#'Convenience for interactive use. Simulation kernels do not call this â€” they
#'use the internal sampler with an explicit, reusable RNG for performance.
#'
#' \subsection{return}{
#'A single numeric (double) draw from the distribution.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `sample_n`}{
#'Draw `n` samples using a thread-local RNG, returned as a numeric vector.
#'
#'Drawing a whole batch in one call avoids per-sample Râ†”Rust overhead, which
#'makes it practical to validate the sampler against large empirical samples
#'(e.g. one million draws) from R.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`n`}{Number of samples to draw; must be non-negative.}
#'}}
#' \subsection{return}{
#'A numeric (double) vector of length `n`.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
Distribution <- new.env(parent = emptyenv())

Distribution$sample_one <- function() .Call(wrap__Distribution__sample_one, self)

Distribution$sample_n <- function(n) .Call(wrap__Distribution__sample_n, self, n)

#' @rdname Distribution
#' @usage NULL
#' @export
`$.Distribution` <- function (self, name) { func <- Distribution[[name]]; environment(func) <- environment(); func }

#' @export
`[[.Distribution` <- `$.Distribution`

#' A Rust-owned, dtype-tagged property array (1-D scalar, or a 2-D vector report).
#'
#' Allocate one with [allocate_scalar()] (`nrows` elements, `ncols == 1`) or
#' [allocate_vector()] (`nrows`-per-slot Ã— `ncols` slots, stored COLUMN-MAJOR so a
#' whole slot/time-slice is contiguous). The data is held in Rust and exposed to
#' R only as an opaque handle; use `$values()` to copy a snapshot back into an R
#' vector (or matrix, when `ncols > 1`) for inspection, `$fill()` / `$set()` to
#' write, and `$length()` / `$dtype()` to query. The simulation step kernels
#' operate on the buffer in place with no copies.
#'
#' @export
#'
#' @section Methods:
#'\subsection{Method `length`}{
#'Number of elements in the array.
#' \subsection{return}{
#'An integer length.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `dtype`}{
#'The element data type as a string (e.g. `"u8"`, `"f32"`).
#' \subsection{return}{
#'A length-1 character vector.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `values`}{
#'Copy the array into an R vector for inspection (NOT a view â€” a snapshot).
#'
#'Integer-width types (i8, u8, i16, u16, i32) widen to R `integer`; `u32`,
#'`f32`, and `f64` widen to R `double` (since `u32` overflows R's signed
#'32-bit integer). This O(n) copy is the only place data leaves Rust.
#'
#'For a 2-D column (`n_slices > 1`, from [allocate_vector()]) the result carries
#'a `dim` attribute and reads back as an `n_slices Ã— slice_len` R matrix (e.g.
#'`n_ticks Ã— n_nodes`), so row `t` is tick `t`'s per-node vector; otherwise a
#'plain vector. The snapshot is transposed during the copy (our buffer is
#'slice-major, R matrices are column-major) â€” inexpensive, inspection-only.
#'
#' \subsection{return}{
#'A numeric vector (or matrix) â€” integer or double â€” of `length()` elements.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `fill`}{
#'Set every element to `value`, cast to the array's data type.
#'
#'For integer-typed arrays the value is truncated toward zero (e.g. `2.9`
#'becomes `2`); out-of-range values wrap per Rust's `as` cast.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`value`}{A single numeric value to broadcast across the array.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `set`}{
#'Overwrite the array from an R numeric vector (integer or double).
#'
#'The input length must equal `length()`. Each element is cast to the array's
#'data type (integer-typed arrays truncate toward zero). Useful for setup â€”
#'e.g. writing per-agent node assignments or seeding initial states from R.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`values`}{A numeric vector of length `length()`.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `col`}{
#'Read one column (`slot`) of a 2-D Column as an R vector snapshot.
#'
#'Returns the `slice_len` values in column `slot` (e.g. all nodes for one tick),
#'widened to R `integer`/`double` like [values()]. For a scalar column the only
#'valid `slot` is 0 (the whole vector).
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`slot`}{0-based column index, less than the number of columns.}
#'}}
#' \subsection{return}{
#'A numeric vector of length `slice_len`.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `set_col`}{
#'Write `values` into one column (`slot`) of a 2-D Column, in place.
#'
#'`values` must have length `slice_len`; each element is cast to the column's
#'data type. Lets the caller update a single column (e.g. one tick's per-node
#'slice â€” a derived population total) without rewriting the whole buffer.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`slot`}{  0-based column index, less than the number of columns.}
#'\item{`values`}{A numeric vector of length `slice_len`.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `squash`}{
#'Compact the first `length(keep)` elements in place, keeping those flagged `TRUE`.
#'
#'Drops elements where `keep` is `FALSE`/`NA`, shifting the survivors to the front
#'(order preserved), and returns the number kept. Use it to reclaim the slots of
#'deceased agents: apply the SAME `keep` mask to every per-agent Column (so they stay
#'aligned) and set the active count to the returned value. The R [squash()] helper
#'does exactly this across a people environment. Only valid for a 1-D (scalar) Column.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`keep`}{A logical vector whose length is at most the column length (typically the active agent count).}
#'}}
#' \subsection{return}{
#'The number of kept elements (an integer); elements past it are left as-is.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
Column <- new.env(parent = emptyenv())

Column$length <- function() .Call(wrap__Column__length, self)

Column$dtype <- function() .Call(wrap__Column__dtype, self)

Column$values <- function() .Call(wrap__Column__values, self)

Column$fill <- function(value) .Call(wrap__Column__fill, self, value)

Column$set <- function(values) .Call(wrap__Column__set, self, values)

Column$col <- function(slot) .Call(wrap__Column__col, self, slot)

Column$set_col <- function(slot, values) .Call(wrap__Column__set_col, self, slot, values)

Column$squash <- function(keep) .Call(wrap__Column__squash, self, keep)

#' @rdname Column
#' @usage NULL
#' @export
`$.Column` <- function (self, name) { func <- Column[[name]]; environment(func) <- environment(); func }

#' @export
`[[.Column` <- `$.Column`

